  1→import { PropsIconsNameCore } from '@semparar/design-system-app';
  2→import { PropsCardTransition } from '@semparar/design-system-app/src/atomic/molecules/CardTransition/Models';
  3→import { propsItemsListCardTransition } from '@semparar/design-system-app/src/atomic/organisms/ListCardTransition/Models';
  4→import { eventSelectContent } from '~/constants/functions';
  5→import type { getPointsExtractApi, TransactionDto } from '../api/extract.api';
  6→import type {
  7→  PointsExtractData,
  8→  PointsTransaction,
  9→  ProcessedExtractData,
 10→  TransactionType,
 11→} from '../models/extract.model';
 12→import { TYPE_LABELS } from '../models/extract.model';
 13→import { moment } from '../moment';
 14→
 15→const TRANSACTION_TYPE_MAP: Record<string, TransactionType> = {
 16→  CREDIT: 'CREDIT',
 17→  RESCUE: 'RESCUE',
 18→  EXPIRED: 'EXPIRED',
 19→  REFUNDED: 'REFUNDED',
 20→};
 21→
 22→const DEFAULT_PROCESSED_EXTRACT_DATA: ProcessedExtractData = {
 23→  groupedTransactions: [],
 24→  mappedTransactions: [],
 25→};
 26→
 27→function getMappedTransactionType(backendType: string): TransactionType {
 28→  return TRANSACTION_TYPE_MAP[backendType] ?? 'CREDIT';
 29→}
 30→
 31→function getFormattedDateForHeader(dateString: string): string {
 32→  return moment(dateString).format('DD [de] MMMM').toLowerCase();
 33→}
 34→
 35→function getFormattedPointsValue(
 36→  amount: number,
 37→  type: TransactionType,
 38→): string {
 39→  const isPositive = type === 'CREDIT' || type === 'REFUNDED';
 40→  const prefix = isPositive ? '+ ' : '- ';
 41→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} pontos`;
 42→}
 43→
 44→function getTransactionDescription(type: TransactionType): string {
 45→  return TYPE_LABELS[type] || '';
 46→}
 47→
 48→function getCapitalizedText(text: string): string {
 49→  if (!text) return text;
 50→  return text.charAt(0).toUpperCase() + text.slice(1).toLowerCase();
 51→}
 52→
 53→function getTransactionCardItem(
 54→  transaction: PointsTransaction,
 55→): PropsCardTransition {
 56→  const isPositive =
 57→    transaction.type === 'CREDIT' || transaction.type === 'REFUNDED';
 58→  const valueColor = isPositive ? 'PLUS_COLOR_02' : 'BRAND_COMPLEMENT_01';
 59→  const isExpired = transaction.type === 'EXPIRED';
 60→
 61→  return {
 62→    type: 'default' as const,
 63→    bgColor: 'INTENSE_COLOR_01' as const,
 64→    titleColor: 'BRAND_COMPLEMENT_01' as const,
 65→    isSelected: true,
 66→    leftIcon: isExpired
 67→      ? 'icon-less'
 68→      : (transaction.icon as PropsIconsNameCore),
 69→    leftIconColor: 'BRAND_COMPLEMENT_01',
 70→    labelBgColor: 'BRAND_COMPLEMENT_03',
 71→    showBackgroundLeftIcon: true,
 72→    title: getCapitalizedText(transaction.description),
 73→    description: undefined,
 74→    value: getFormattedPointsValue(transaction.amount, transaction.type),
 75→    valueColor,
 76→    descriptionSecondary: getTransactionDescription(transaction.type),
 77→    descriptionSecondaryColor: 'INTENSE_COLOR_04',
 78→    showIcon: true,
 79→    rightIcon: 'icon-next',
 80→    showRightIcon: !isExpired,
 81→    onPressDetail: () => {
 82→      eventSelectContent({
 83→        content_type: 'cta',
 84→        content_id: 'detalhe_ponto',
 85→        location_1: 'monetizacao',
 86→        location_2: 'hub_recompensas_spmais',
 87→        location_3: 'extrato_hub_recompensas',
 88→      });
 89→    },
 90→  };
 91→}
 92→
 93→interface GroupedTransactions {
 94→  date: string;
 95→  items: propsItemsListCardTransition[];
 96→}
 97→
 98→function getGroupedTransactionsByDate(
 99→  transactions: PointsTransaction[],
100→): GroupedTransactions[] {
101→  if (transactions.length === 0) {
102→    return [];
103→  }
104→
105→  const sortedTransactions = [...transactions].sort((a, b) =>
106→    moment(b.date).diff(moment(a.date)));
107→
108→  const groupedByDate = sortedTransactions.reduce(
109→    (acc, transaction) => {
110→      const formattedDate = getFormattedDateForHeader(transaction.date);
111→
112→      if (!acc[formattedDate]) {
113→        acc[formattedDate] = [];
114→      }
115→
116→      acc[formattedDate].push(
117→        getTransactionCardItem(transaction) as propsItemsListCardTransition,
118→      );
119→      return acc;
120→    },
121→    {} as Record<string, propsItemsListCardTransition[]>,
122→  );
123→
124→  const getSortedItemsByDate = (
125→    items: propsItemsListCardTransition[],
126→    date: string,
127→  ) => {
128→    return items.sort((a, b) => {
129→      const transactionA = sortedTransactions.find(
130→        t =>
131→          getFormattedDateForHeader(t.date) === date &&
132→          getTransactionCardItem(t).title === a.title,
133→      );
134→      const transactionB = sortedTransactions.find(
135→        t =>
136→          getFormattedDateForHeader(t.date) === date &&
137→          getTransactionCardItem(t).title === b.title,
138→      );
139→
140→      if (transactionA && transactionB) {
141→        return moment(transactionB.date).diff(moment(transactionA.date));
142→      }
143→      return 0;
144→    });
145→  };
146→
147→  const getSortedByDate = (a: GroupedTransactions, b: GroupedTransactions) => {
148→    const dateA = moment(a.date.split(' ').slice(1).join(' '), 'DD MMMM');
149→    const dateB = moment(b.date.split(' ').slice(1).join(' '), 'DD MMMM');
150→    return dateB.diff(dateA);
151→  };
152→
153→  return Object.entries(groupedByDate)
154→    .map(([date, items]) => ({
155→      date,
156→      items: getSortedItemsByDate(
157→        items as propsItemsListCardTransition[],
158→        date,
159→      ),
160→    }))
161→    .sort(getSortedByDate);
162→}
163→
164→class PointsDataGroupedByDayMapper {
165→  public static getMappedData(
166→    groupedData: Array<{
167→      date: string;
168→      items: propsItemsListCardTransition[];
169→    }>,
170→    showLabels = true,
171→  ): propsItemsListCardTransition[] {
172→    if (!groupedData || groupedData.length === 0) return [];
173→
174→    return groupedData.flatMap(({ date: label, items }) =>
175→      (items ?? []).map((item, index) => ({
176→        ...item,
177→        label,
178→        showLabel: showLabels ? index === 0 : false,
179→      }))) as propsItemsListCardTransition[];
180→  }
181→}
182→
183→function getTransactionFromDto(dto: TransactionDto): PointsTransaction {
184→  return {
185→    id: dto.id,
186→    date: dto.date,
187→    description: dto.description,
188→    type: getMappedTransactionType(dto.type),
189→    amount: dto.amount,
190→    currencyValue: 0,
191→    icon: dto.icon,
192→    details: {
193→      provider: '',
194→      extraInfo: '',
195→      fields: [],
196→    },
197→    status: dto.status ?? '',
198→  };
199→}
200→
201→export function processPointsExtractData(
202→  extractData: PointsExtractData | null | undefined,
203→): ProcessedExtractData {
204→  if (!extractData || typeof extractData !== 'object') {
205→    return DEFAULT_PROCESSED_EXTRACT_DATA;
206→  }
207→
208→  try {
209→    const transactions = extractData.transactions || [];
210→    const groupedTransactions = getGroupedTransactionsByDate(transactions);
211→    const mappedTransactions =
212→      PointsDataGroupedByDayMapper.getMappedData(groupedTransactions);
213→
214→    return {
215→      groupedTransactions,
216→      mappedTransactions,
217→    };
218→  } catch (error) {
219→    console.warn('Erro ao processar dados do extrato:', error);
220→    return DEFAULT_PROCESSED_EXTRACT_DATA;
221→  }
222→}
223→
224→export function getPointsExtractFromResponse(
225→  response: Awaited<ReturnType<typeof getPointsExtractApi>>,
226→): PointsExtractData | null {
227→  const apiResponse = response?.data;
228→
229→  if (!apiResponse) {
230→    return null;
231→  }
232→
233→  const transactionsContainer = apiResponse.data ?? apiResponse;
234→  const transactionsDto = transactionsContainer?.transactions;
235→  const pagination =
236→    apiResponse.pagination ?? (apiResponse as any).data?.pagination;
237→
238→  if (!transactionsDto || !Array.isArray(transactionsDto)) {
239→    return null;
240→  }
241→
242→  if (!pagination) {
243→    return null;
244→  }
245→
246→  const transactions = transactionsDto.map(getTransactionFromDto);
247→
248→  return {
249→    transactions,
250→    pagination,
251→  };
252→}
