430→          {
431→            label: '30 dias',
432→            value: 2,
433→          },
434→          {
435→            label: '60 dias',
436→            value: 3,
437→          },
438→          {
439→            label: '90 dias',
440→            value: 4,
441→          },
442→        ],
443→      },
444→      {
445→        label: 'Tipos de lançamentos',
446→        options: [
447→          {
448→            label: 'Ganhos',
449→            value: 'CREDIT',
450→          },
451→          {
452→            label: 'Usados',
